[SRSReportParameterAttribute(classStr(ETGScaleTicketReportContract))]
internal final class ETGScaleTicketReportDP extends SRSReportDataProviderBase
{
    ETGScaleTicketReportTmp scaleTmp;

}

Method.Source:
public void processReport()
{
    ETGScaleTicketTable table;
    ETGScaleTicketReportContract contract = this.parmDataContract() as ETGScaleTicketReportContract;
    select firstonly table
        where table.ScaleTicketNumber == contract.parmScaleTicketNum();

    scaleTmp.clear();
    scaleTmp.ScaleTicketNumber = table.ScaleTicketNumber;
    scaleTmp.Location          = table.Location;
    scaleTmp.BranchLocation   = table.BranchLocation;
    scaleTmp.ScaleUsed        = table.ScaleUsed;
    scaleTmp.Producer         = table.Producer;
    scaleTmp.CarrierInfo      = table.CarrierInfo;
    scaleTmp.Commodity        = table.Commodity;
    scaleTmp.Bin              = table.Bin;
    scaleTmp.LastHauled       = table.LastHauled;
    scaleTmp.Operator         = table.Operator;
    scaleTmp.InspectedBy      = table.InspectedBy;
    scaleTmp.Gross            = table.Gross;
    scaleTmp.Tare             = table.Tare;
    scaleTmp.Net              = table.Net;
    scaleTmp.GradedAs         = table.GradedAs;
    scaleTmp.Grading          = table.Grader;
    scaleTmp.Dockage          = table.Dockage;
    scaleTmp.Moisture         = table.Moisture;
    scaleTmp.Damage           = table.Damage;
    scaleTmp.Shrinkage        = table.Shrinkage;
    scaleTmp.Splits           = table.Splits;
    scaleTmp.Notes            = table.Notes;
    scaleTmp.PrintedDateTime  = DateTimeUtil::getSystemDateTime();
    scaleTmp.Unit             = table.Unit;

    CompanyInfo companyInfo = CompanyInfo::find();
    scaleTmp.CompanyLogo    = CompanyImage::findByRecord(companyInfo).Image;
    scaleTmp.insert();
}
